import lxml.etree as ET
from defusedxml import cElementTree as DT

def process_soap_request(soap_envelope):
    # Parse the SOAP envelope using lxml
    soap_root = ET.fromstring(soap_envelope)
    
    # Validate the XML against the DTD using defusedxml
    DT.parse(soap_root.getroottree().docinfo.ExternalID, soap_root)
    
